def count_connected_components(graph):
    num_components = 0
    visited = set()

    def dfs(node):
        visited.add(node)
        for neighbor in graph[node]:
            if neighbor not in visited:
                dfs(neighbor)

    for node in graph:
        if node not in visited:
            num_components += 1
            dfs(node)

    return num_components
